import{_ as t,a,b as d,c as n}from"./chunks/授权后复制刷新令牌.DFAJxpN4.js";import{_ as o,o as s,c as i,a2 as l}from"./chunks/framework.DnrXFDHb.js";const k=JSON.parse('{"title":"Yandex Channel যোগ করা","description":"","frontmatter":{},"headers":[],"relativePath":"bn-BD/upload/yandex.md","filePath":"bn-BD/upload/yandex.md","lastUpdated":1781962217000}'),r={name:"bn-BD/upload/yandex.md"};function p(c,e,h,u,m,b){return s(),i("div",null,[...e[0]||(e[0]=[l('<h1 id="yandex-channel-যোগ-করা" tabindex="-1">Yandex Channel যোগ করা <a class="header-anchor" href="#yandex-channel-যোগ-করা" aria-label="Permalink to &quot;Yandex Channel যোগ করা&quot;">​</a></h1><h2 id="আগে-যা-লাগবে" tabindex="-1">আগে যা লাগবে <a class="header-anchor" href="#আগে-যা-লাগবে" aria-label="Permalink to &quot;আগে যা লাগবে&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Requirement</th><th>কেন লাগবে</th></tr></thead><tbody><tr><td>Yandex account</td><td>Sign in এবং Yandex Disk authorize করতে লাগে</td></tr><tr><td>Yandex OAuth app</td><td><code>Client ID</code> এবং <code>Client Secret</code> generate করতে লাগে</td></tr><tr><td>আপনার ImgBed domain</td><td>OAuth redirect URI-এর জন্য লাগে</td></tr><tr><td>Available Yandex Disk storage</td><td>Actual file storage location হিসেবে ব্যবহৃত হবে</td></tr></tbody></table><h2 id="setup-steps" tabindex="-1">Setup Steps <a class="header-anchor" href="#setup-steps" aria-label="Permalink to &quot;Setup Steps&quot;">​</a></h2><h3 id="step-1-yandex-oauth-app-তৈরি-করুন" tabindex="-1">Step 1: Yandex OAuth App তৈরি করুন <a class="header-anchor" href="#step-1-yandex-oauth-app-তৈরি-করুন" aria-label="Permalink to &quot;Step 1: Yandex OAuth App তৈরি করুন&quot;">​</a></h3><ol><li>Yandex OAuth app creation page খুলুন:</li></ol><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://oauth.yandex.com/client/new</span></span></code></pre></div><ol start="2"><li>Sign in page-এ redirect হলে আগে Yandex account দিয়ে sign in করুন।</li><li>নতুন app তৈরি করুন।</li><li>App-এর চেনা যায় এমন নাম দিন, যেমন <code>imgbed-yandex</code>।</li><li>Callback বা redirect URL settings খুঁজুন।</li><li>দিন:</li></ol><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://your-domain.com/api/oauth/yandex/callback</span></span></code></pre></div><h3 id="step-2-permissions-confirm-করুন" tabindex="-1">Step 2: Permissions Confirm করুন <a class="header-anchor" href="#step-2-permissions-confirm-করুন" aria-label="Permalink to &quot;Step 2: Permissions Confirm করুন&quot;">​</a></h3><p>বর্তমান ImgBed Yandex integration-এর জন্য <code>Yandex.Disk REST API</code>-এর নিচে এই চারটি permissions রাখুন:</p><table tabindex="0"><thead><tr><th>Permission</th><th>Purpose</th></tr></thead><tbody><tr><td><code>cloud_api:disk.app_folder</code></td><td>ImgBed-কে app folder-এ files store করতে দেয়</td></tr><tr><td><code>cloud_api:disk.read</code></td><td>Files এবং download links পড়ে</td></tr><tr><td><code>cloud_api:disk.write</code></td><td>Files upload, folders create এবং files delete করে</td></tr><tr><td><code>Access to information about Yandex.Disk</code></td><td>Disk quota এবং used space পড়ে</td></tr></tbody></table><p><code>Yandex ID API</code>-এর নিচে এগুলো দেখলে optional:</p><table tabindex="0"><thead><tr><th>Permission Text</th><th>Recommendation</th></tr></thead><tbody><tr><td><code>Access to username, first name and surname, gender</code></td><td>Optional</td></tr><tr><td><code>Access to email address</code></td><td>Optional</td></tr></tbody></table><p>Core upload, download, deletion এবং quota features মূলত উপরের চারটি <code>Yandex.Disk REST API</code> permissions-এর ওপর নির্ভর করে।</p><p><img src="'+t+'" alt="Configure Yandex Disk permissions" loading="lazy"></p><h3 id="step-3-app-credentials-copy-করুন" tabindex="-1">Step 3: App Credentials Copy করুন <a class="header-anchor" href="#step-3-app-credentials-copy-করুন" aria-label="Permalink to &quot;Step 3: App Credentials Copy করুন&quot;">​</a></h3><p>App তৈরি হলে copy করুন:</p><table tabindex="0"><thead><tr><th>Yandex Field</th><th>ImgBed Field</th></tr></thead><tbody><tr><td><code>Client ID</code></td><td><code>Client ID</code></td></tr><tr><td><code>Client Secret</code></td><td><code>Client Secret</code></td></tr></tbody></table><p><img src="'+a+'" alt="Record Client ID and Secret" loading="lazy"></p><h3 id="step-4-yandex-channel-পূরণ-করুন" tabindex="-1">Step 4: Yandex Channel পূরণ করুন <a class="header-anchor" href="#step-4-yandex-channel-পূরণ-করুন" aria-label="Permalink to &quot;Step 4: Yandex Channel পূরণ করুন&quot;">​</a></h3><p>Upload Settings-এ <code>Yandex</code> নির্বাচন করে পূরণ করুন:</p><table tabindex="0"><thead><tr><th>ImgBed Field</th><th>কী দেবেন</th></tr></thead><tbody><tr><td>Channel name</td><td>চেনা যায় এমন নাম, যেমন <code>Main Yandex</code></td></tr><tr><td>Client ID</td><td>Yandex app <code>Client ID</code></td></tr><tr><td>Client Secret</td><td>Yandex app <code>Client Secret</code></td></tr><tr><td>Refresh Token</td><td>আপাতত empty রাখুন</td></tr><tr><td>Root directory</td><td>Optional। Default <code>imgbed</code>।</td></tr></tbody></table><p><img src="'+d+'" alt="Edit channel config" loading="lazy"></p><h3 id="step-5-refresh-token-নিন" tabindex="-1">Step 5: Refresh Token নিন <a class="header-anchor" href="#step-5-refresh-token-নিন" aria-label="Permalink to &quot;Step 5: Refresh Token নিন&quot;">​</a></h3><ol><li>ImgBed-এ <code>Get Token</code> ক্লিক করুন।</li><li>যে Yandex account connect করতে চান সেটিতে sign in করুন।</li><li>Authorization prompt approve করুন।</li><li>Callback page একটি <code>Refresh Token</code> দেখাবে।</li><li>সেটি copy করুন।</li><li>ImgBed-এ ফিরে <code>Refresh Token</code> field-এ paste করুন।</li></ol><p><img src="'+n+`" alt="Copy refresh token after authorization" loading="lazy"></p><h3 id="step-6-channel-save-করুন" tabindex="-1">Step 6: Channel Save করুন <a class="header-anchor" href="#step-6-channel-save-করুন" aria-label="Permalink to &quot;Step 6: Channel Save করুন&quot;">​</a></h3><p>সব fields পূরণ হলে channel save করুন।</p><h2 id="quick-flow" tabindex="-1">Quick Flow <a class="header-anchor" href="#quick-flow" aria-label="Permalink to &quot;Quick Flow&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Yandex OAuth Console খুলুন</span></span>
<span class="line"><span>-&gt; App তৈরি করুন</span></span>
<span class="line"><span>-&gt; https://your-domain.com/api/oauth/yandex/callback যোগ করুন</span></span>
<span class="line"><span>-&gt; Yandex Disk permissions confirm করুন</span></span>
<span class="line"><span>-&gt; Client ID এবং Client Secret copy করুন</span></span>
<span class="line"><span>-&gt; ImgBed-এ Client ID / Client Secret পূরণ করুন</span></span>
<span class="line"><span>-&gt; Get Token ক্লিক করুন</span></span>
<span class="line"><span>-&gt; Callback page থেকে Refresh Token copy করুন</span></span>
<span class="line"><span>-&gt; ImgBed-এ paste করে save করুন</span></span></code></pre></div><h2 id="references" tabindex="-1">References <a class="header-anchor" href="#references" aria-label="Permalink to &quot;References&quot;">​</a></h2><ol><li>Register a Yandex app: <a href="https://yandex.com/dev/id/doc/en/register-client" target="_blank" rel="noreferrer">https://yandex.com/dev/id/doc/en/register-client</a></li><li>Get an authorization code through URL: <a href="https://yandex.com/dev/id/doc/en/codes/code-url" target="_blank" rel="noreferrer">https://yandex.com/dev/id/doc/en/codes/code-url</a></li><li>Yandex OAuth token endpoint: <a href="https://yandex.com/dev/id/doc/en/tokens/token" target="_blank" rel="noreferrer">https://yandex.com/dev/id/doc/en/tokens/token</a></li></ol>`,33)])])}const f=o(r,[["render",p]]);export{k as __pageData,f as default};
